1	/**
2	 * LayerInfinite MCP Server — rest-client.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * V2: LiApiClient (LI REST API) + UpstreamMCPClient (MCP JSON-RPC proxy).
5	 *
6	 * LiApiClient replaces V1 RestClient — fetches scores, policy decisions,
7	 * and logs outcomes to the LayerInfinite REST API.
8	 *
9	 * UpstreamMCPClient implements MCP JSON-RPC over HTTP for proxying
10	 * tools/list and tools/call to upstream MCP servers, with circuit
11	 * breaker integration and session caching.
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import type { GatewayConfig, UpstreamServer } from './config.js';
16	import type { ScoredAction, PolicyDecision, OutcomePayload } from './types.js';
17	import { UpstreamRegistry } from './upstream-registry.js';
18	import type { FailOpenState } from './types.js';
19	import {
20	  recordUpstreamSuccess,
21	  recordUpstreamFailure,
22	} from './fail-open.js';
23	import { logger } from './logger.js';
24	
25	const log = logger.forTool('rest-client');
26	
27	// ── V1-compatible types (preserved) ──────────────────────────
28	
29	export interface LIApiError {
30	  error: string;
31	  code: string;
32	  message?: string;
33	  details?: unknown;
34	}
35	
36	export interface LIApiResponse<T> {
37	  ok: true;
38	  status: number;
39	  data: T;
40	}
41	
42	export interface LIApiErrorResponse {
43	  ok: false;
44	  status: number;
45	  error: LIApiError;
46	}
47	
48	export type LIResult<T> = LIApiResponse<T> | LIApiErrorResponse;
49	
50	// ── V2 new types ─────────────────────────────────────────────
51	
52	export interface RawUpstreamTool {
53	  name: string;
54	  description: string;
55	  inputSchema: Record<string, unknown>;
56	  upstreamName: string;
57	}
58	
59	export interface UpstreamCallResult {
60	  content: Array<{ type: string; [key: string]: unknown }>;
61	  isError?: boolean;
62	}
63	
64	// ── Constants ────────────────────────────────────────────────
65	
66	const LI_API_TIMEOUT_MS = 15_000;
67	const MCP_CALL_TIMEOUT_MS = 30_000;
68	const RETRYABLE_STATUS_CODES = new Set([429, 502, 503, 504]);
69	const MAX_RETRIES = 2;
70	const BASE_RETRY_DELAY_MS = 500;
71	
72	// Per-upstream connection concurrency
73	const DEFAULT_MAX_CONCURRENT_UPSTREAM = 100;
74	
75	function getMaxConcurrentUpstream(): number {
76	  const v = Number.parseInt(process.env.LAYERINFINITE_MAX_UPSTREAM_CONCURRENT ?? '', 10);
77	  return Number.isFinite(v) && v > 0 ? v : DEFAULT_MAX_CONCURRENT_UPSTREAM;
78	}
79	
80	// ══════════════════════════════════════════════════════════════
81	// LiApiClient — LI REST API communication
82	// ══════════════════════════════════════════════════════════════
83	
84	export class LiApiClient {
85	  private readonly baseUrl: string;
86	  private readonly headers: Record<string, string>;
87	
88	  constructor(config: GatewayConfig) {
89	    this.baseUrl = config.baseUrl;
90	    this.headers = {
91	      'X-API-Key': config.apiKey,
92	      'Content-Type': 'application/json',
93	      'User-Agent': '@layerinfinite/mcp-server/2.0.0',
94	    };
95	  }
96	
97	  /** Fetch scored actions for a task type. */
98	  async getScores(
99	    taskType: string,
100	    customerId: string,
101	    agentId: string,
102	  ): Promise<ScoredAction[]> {
103	    const result = await this.get<{ scores: ScoredAction[] }>(
104	      '/v1/get-scores',
105	      { task_type: taskType, customer_id: customerId, agent_id: agentId },
106	    );
107	    if (!result.ok) {
108	      log.warn('getScores failed', { code: result.error.code });
109	      return [];
110	    }
111	    return result.data.scores ?? [];
112	  }
113	
114	  /** Fetch policy decision for a task type. */
115	  async getPolicyDecision(
116	    taskType: string,
117	    customerId: string,
118	    agentId: string,
119	  ): Promise<PolicyDecision | null> {
120	    const result = await this.get<{ decision: PolicyDecision | null }>(
121	      '/v1/recommendations',
122	      { task_type: taskType, customer_id: customerId, agent_id: agentId },
123	    );
124	    if (!result.ok) {
125	      log.warn('getPolicyDecision failed', { code: result.error.code });
126	      return null;
127	    }
128	    return result.data.decision ?? null;
129	  }
130	
131	  /** Fire-and-forget outcome logging. Returns true if successful. */
132	  async logOutcome(payload: OutcomePayload): Promise<boolean> {
133	    const result = await this.post<{ accepted: boolean }>(
134	      '/v1/log-outcome',
135	      payload as unknown as Record<string, unknown>,
136	    );
137	    return result.ok;
138	  }
139	
140	  /** Get recommendations for a task type (legacy / li_recommend support). */
141	  async getRecommendations(
142	    taskType: string,
143	    customerId: string,
144	    agentId: string,
145	  ): Promise<ScoredAction[]> {
146	    return this.getScores(taskType, customerId, agentId);
147	  }
148	
149	  // ── HTTP helpers (preserved from V1) ─────────────────────
150	
151	  private async get<T>(
152	    path: string,
153	    params?: Record<string, string>,
154	  ): Promise<LIResult<T>> {
155	    const url = new URL(`${this.baseUrl}${path}`);
156	    if (params) {
157	      for (const [key, value] of Object.entries(params)) {
158	        if (value !== undefined && value !== '') {
159	          url.searchParams.set(key, value);
160	        }
161	      }
162	    }
163	    return this.requestWithRetry<T>(url.toString(), { method: 'GET' });
164	  }
165	
166	  private async post<T>(
167	    path: string,
168	    body: Record<string, unknown>,
169	  ): Promise<LIResult<T>> {
170	    return this.requestWithRetry<T>(`${this.baseUrl}${path}`, {
171	      method: 'POST',
172	      body: JSON.stringify(body),
173	    });
174	  }
175	
176	  private async requestWithRetry<T>(
177	    url: string,
178	    init: RequestInit,
179	  ): Promise<LIResult<T>> {
180	    let lastResult: LIResult<T> | null = null;
181	
182	    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
183	      if (attempt > 0) {
184	        const delay = BASE_RETRY_DELAY_MS * Math.pow(2, attempt - 1);
185	        log.warn('Retrying LI API request', { url, attempt: attempt + 1, delay_ms: delay });
186	        await this.sleep(delay);
187	      }
188	
189	      const result = await this.request<T>(url, init);
190	      if (result.ok) return result;
191	
192	      lastResult = result;
193	      const isRetryable = RETRYABLE_STATUS_CODES.has(result.status)
194	        || result.error.code === 'TIMEOUT'
195	        || result.error.code === 'NETWORK_ERROR';
196	      if (!isRetryable) break;
197	    }
198	
199	    return lastResult!;
200	  }
201	
202	  private async request<T>(
203	    url: string,
204	    init: RequestInit,
205	  ): Promise<LIResult<T>> {
206	    const controller = new AbortController();
207	    const timeout = setTimeout(() => controller.abort(), LI_API_TIMEOUT_MS);
208	    const startMs = Date.now();
209	
210	    try {
211	      const response = await fetch(url, {
212	        ...init,
213	        headers: { ...this.headers, ...(init.headers as Record<string, string> ?? {}) },
214	        signal: controller.signal,
215	      });
216	
217	      const latencyMs = Date.now() - startMs;
218	      const isJson = response.headers.get('content-type')?.includes('application/json');
219	
220	      if (response.ok) {
221	        const data = isJson ? (await response.json()) as T : ({} as T);
222	        log.debug('LI API response', { method: init.method, url, status: response.status, latency_ms: latencyMs });
223	        return { ok: true, status: response.status, data };
224	      }
225	
226	      const errorBody: LIApiError = isJson
227	        ? (await response.json()) as LIApiError
228	        : { error: 'API Error', code: 'UNKNOWN', message: await response.text() };
229	
230	      log.warn('LI API error', { method: init.method, url, status: response.status, error_code: errorBody.code });
231	      return { ok: false, status: response.status, error: errorBody };
232	    } catch (err) {
233	      const latencyMs = Date.now() - startMs;
234	      if (err instanceof DOMException && err.name === 'AbortError') {
235	        log.error('LI API timeout', { method: init.method, url, timeout_ms: LI_API_TIMEOUT_MS });
236	        return {
237	          ok: false,
238	          status: 0,
239	          error: { error: 'Request timed out', code: 'TIMEOUT', message: `Request timed out after ${LI_API_TIMEOUT_MS}ms` },
240	        };
241	      }
242	
243	      const message = err instanceof Error ? err.message : String(err);
244	      log.error('LI API network error', { method: init.method, url, error: message });
245	      return {
246	        ok: false,
247	        status: 0,
248	        error: { error: 'Network error', code: 'NETWORK_ERROR', message },
249	      };
250	    } finally {
251	      clearTimeout(timeout);
252	    }
253	  }
254	
255	  private sleep(ms: number): Promise<void> {
256	    return new Promise((resolve) => setTimeout(resolve, ms));
257	  }
258	}
